// Package sqlc provides database query interfaces (generated by sqlc).
package sqlc

import (
	"context"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgtype"
)

// DBTX is the interface for database transactions
type DBTX interface {
	Query(ctx context.Context, sql string, args ...interface{}) (pgx.Rows, error)
	QueryRow(ctx context.Context, sql string, args ...interface{}) pgx.Row
}

// Queries provides database query methods
type Queries struct {
	db DBTX
}

// New creates a new Queries instance
func New(db DBTX) *Queries {
	return &Queries{db: db}
}

// WithTx creates a new Queries instance that uses the given transaction
func (q *Queries) WithTx(tx pgx.Tx) *Queries {
	return &Queries{db: tx}
}

// NewQueries creates a new Queries instance from a querier
func NewQueries(querier interface{}) *Queries {
	return &Queries{}
}

// ModelEndpoint represents an endpoint model
type ModelEndpoint struct {
	ID                uuid.UUID
	Provider          string
	Model             string
	AccountID         string
	ModelID           string
	Status            *string
	PricingBasis      *string
	UnitPriceInput    *pgtype.Numeric
	UnitPriceOutput   *pgtype.Numeric
	LatencyEstimateMs *int32
	Priority          *int32
	QualityTier       *string
}

// ProviderAccount represents a provider account
type ProviderAccount struct {
	ID           string
	Provider     string
	Account      string
	Name         string
	BillingModel string
}

// ProviderAccountLimit represents rate limits for a provider account
type ProviderAccountLimit struct {
	ID              string
	AccountID       string
	LimitType       string
	WindowSeconds   int32
	LimitValue      pgtype.Numeric
	IsHard          *bool
	CooldownSeconds *int32
}

